export function emitJavaContext(packageName: string): string {
  return [
    "// Code generated by Typra emitter; DO NOT EDIT.",
    `package ${packageName};`,
    "",
    "import java.util.Map;",
    "import java.util.function.Function;",
    "",
    "public final class LoadContext {",
    "  private final Function<Object, Object> preProcess;",
    "  private final Function<Object, Object> postProcess;",
    "",
    "  public LoadContext() {",
    "    this(null, null);",
    "  }",
    "",
    "  public LoadContext(Function<Object, Object> preProcess, Function<Object, Object> postProcess) {",
    "    this.preProcess = preProcess;",
    "    this.postProcess = postProcess;",
    "  }",
    "",
    "  public Object processInput(Object value) {",
    "    return preProcess == null ? value : preProcess.apply(value);",
    "  }",
    "",
    "  @SuppressWarnings(\"unchecked\")",
    "  public <T> T processOutput(T value) {",
    "    return postProcess == null ? value : (T) postProcess.apply(value);",
    "  }",
    "}",
    "",
  ].join("\n");
}

export function emitJavaSaveContext(packageName: string): string {
  return [
    "// Code generated by Typra emitter; DO NOT EDIT.",
    `package ${packageName};`,
    "",
    "import java.util.Map;",
    "import java.util.function.Function;",
    "",
    "public final class SaveContext {",
    "  private final Function<Object, Object> preSave;",
    "  private final Function<Map<String, Object>, Map<String, Object>> postSave;",
    "",
    "  public SaveContext() {",
    "    this(null, null);",
    "  }",
    "",
    "  public SaveContext(Function<Object, Object> preSave, Function<Map<String, Object>, Map<String, Object>> postSave) {",
    "    this.preSave = preSave;",
    "    this.postSave = postSave;",
    "  }",
    "",
    "  @SuppressWarnings(\"unchecked\")",
    "  public <T> T processObject(T value) {",
    "    return preSave == null ? value : (T) preSave.apply(value);",
    "  }",
    "",
    "  public Map<String, Object> processDict(Map<String, Object> value) {",
    "    return postSave == null ? value : postSave.apply(value);",
    "  }",
    "}",
    "",
  ].join("\n");
}

export function emitJavaMaps(packageName: string): string {
  return [
    "// Code generated by Typra emitter; DO NOT EDIT.",
    `package ${packageName};`,
    "",
    "import java.util.LinkedHashMap;",
    "import java.util.Map;",
    "",
    "public final class TypraMaps {",
    "  private TypraMaps() { }",
    "",
    "  public static Map<String, Object> mapOf(Object... pairs) {",
    "    Map<String, Object> result = new LinkedHashMap<>();",
    "    for (int i = 0; i + 1 < pairs.length; i += 2) {",
    "      result.put(String.valueOf(pairs[i]), pairs[i + 1]);",
    "    }",
    "    return result;",
    "  }",
    "}",
    "",
  ].join("\n");
}

export function emitJavaJson(packageName: string): string {
  return [
    "// Code generated by Typra emitter; DO NOT EDIT.",
    `package ${packageName};`,
    "",
    "import java.util.Iterator;",
    "import java.util.ArrayList;",
    "import java.util.LinkedHashMap;",
    "import java.util.List;",
    "import java.util.Map;",
    "",
    "public final class TypraJson {",
    "  private TypraJson() { }",
    "",
    "  public static String stringify(Object value) {",
    "    if (value == null) return \"null\";",
    "    if (value instanceof String s) return \"\\\"\" + escape(s) + \"\\\"\";",
    "    if (value instanceof Number || value instanceof Boolean) return String.valueOf(value);",
    "    if (value instanceof Map<?, ?> map) {",
    "      StringBuilder builder = new StringBuilder(\"{\");",
    "      Iterator<? extends Map.Entry<?, ?>> iterator = map.entrySet().iterator();",
    "      while (iterator.hasNext()) {",
    "        Map.Entry<?, ?> entry = iterator.next();",
    "        builder.append(stringify(String.valueOf(entry.getKey()))).append(':').append(stringify(entry.getValue()));",
    "        if (iterator.hasNext()) builder.append(',');",
    "      }",
    "      return builder.append('}').toString();",
    "    }",
    "    if (value instanceof Iterable<?> iterable) {",
    "      StringBuilder builder = new StringBuilder(\"[\");",
    "      Iterator<?> iterator = iterable.iterator();",
    "      while (iterator.hasNext()) {",
    "        builder.append(stringify(iterator.next()));",
    "        if (iterator.hasNext()) builder.append(',');",
    "      }",
    "      return builder.append(']').toString();",
    "    }",
    "    return stringify(String.valueOf(value));",
    "  }",
    "",
    "  public static Object parse(String json) {",
    "    Parser parser = new Parser(json);",
    "    Object value = parser.parseValue();",
    "    parser.skipWhitespace();",
    "    if (!parser.isAtEnd()) {",
    "      throw new IllegalArgumentException(\"Unexpected trailing JSON content at offset \" + parser.index);",
    "    }",
    "    return value;",
    "  }",
    "",
    "  private static String escape(String value) {",
    "    return value.replace(\"\\\\\", \"\\\\\\\\\").replace(\"\\\"\", \"\\\\\\\"\").replace(\"\\r\", \"\\\\r\").replace(\"\\n\", \"\\\\n\");",
    "  }",
    "",
    "  private static final class Parser {",
    "    private final String input;",
    "    private int index;",
    "",
    "    Parser(String input) {",
    "      this.input = input == null ? \"\" : input;",
    "    }",
    "",
    "    boolean isAtEnd() {",
    "      return index >= input.length();",
    "    }",
    "",
    "    void skipWhitespace() {",
    "      while (!isAtEnd() && Character.isWhitespace(input.charAt(index))) index++;",
    "    }",
    "",
    "    Object parseValue() {",
    "      skipWhitespace();",
    "      if (isAtEnd()) throw error(\"Unexpected end of JSON input\");",
    "      char ch = input.charAt(index);",
    "      if (ch == '{') return parseObject();",
    "      if (ch == '[') return parseArray();",
    "      if (ch == '\"') return parseString();",
    "      if (ch == 't') return parseLiteral(\"true\", Boolean.TRUE);",
    "      if (ch == 'f') return parseLiteral(\"false\", Boolean.FALSE);",
    "      if (ch == 'n') return parseLiteral(\"null\", null);",
    "      if (ch == '-' || Character.isDigit(ch)) return parseNumber();",
    "      throw error(\"Unexpected JSON token\");",
    "    }",
    "",
    "    private Map<String, Object> parseObject() {",
    "      expect('{');",
    "      Map<String, Object> result = new LinkedHashMap<>();",
    "      skipWhitespace();",
    "      if (tryConsume('}')) return result;",
    "      while (true) {",
    "        skipWhitespace();",
    "        String key = parseString();",
    "        skipWhitespace();",
    "        expect(':');",
    "        result.put(key, parseValue());",
    "        skipWhitespace();",
    "        if (tryConsume('}')) return result;",
    "        expect(',');",
    "      }",
    "    }",
    "",
    "    private List<Object> parseArray() {",
    "      expect('[');",
    "      List<Object> result = new ArrayList<>();",
    "      skipWhitespace();",
    "      if (tryConsume(']')) return result;",
    "      while (true) {",
    "        result.add(parseValue());",
    "        skipWhitespace();",
    "        if (tryConsume(']')) return result;",
    "        expect(',');",
    "      }",
    "    }",
    "",
    "    private String parseString() {",
    "      expect('\"');",
    "      StringBuilder result = new StringBuilder();",
    "      while (!isAtEnd()) {",
    "        char ch = input.charAt(index++);",
    "        if (ch == '\"') return result.toString();",
    "        if (ch != '\\\\') {",
    "          result.append(ch);",
    "          continue;",
    "        }",
    "        if (isAtEnd()) throw error(\"Unterminated JSON escape sequence\");",
    "        char escaped = input.charAt(index++);",
    "        switch (escaped) {",
    "          case '\"' -> result.append('\"');",
    "          case '\\\\' -> result.append('\\\\');",
    "          case '/' -> result.append('/');",
    "          case 'b' -> result.append('\\b');",
    "          case 'f' -> result.append('\\f');",
    "          case 'n' -> result.append('\\n');",
    "          case 'r' -> result.append('\\r');",
    "          case 't' -> result.append('\\t');",
    "          case 'u' -> result.append(parseUnicodeEscape());",
    "          default -> throw error(\"Unsupported JSON escape sequence\");",
    "        }",
    "      }",
    "      throw error(\"Unterminated JSON string\");",
    "    }",
    "",
    "    private char parseUnicodeEscape() {",
    "      if (index + 4 > input.length()) throw error(\"Incomplete unicode escape\");",
    "      String hex = input.substring(index, index + 4);",
    "      index += 4;",
    "      try {",
    "        return (char) Integer.parseInt(hex, 16);",
    "      } catch (NumberFormatException error) {",
    "        throw error(\"Invalid unicode escape\");",
    "      }",
    "    }",
    "",
    "    private Object parseLiteral(String literal, Object value) {",
    "      if (!input.startsWith(literal, index)) throw error(\"Invalid JSON literal\");",
    "      index += literal.length();",
    "      return value;",
    "    }",
    "",
    "    private Number parseNumber() {",
    "      int start = index;",
    "      if (input.charAt(index) == '-') index++;",
    "      while (!isAtEnd() && Character.isDigit(input.charAt(index))) index++;",
    "      boolean floating = false;",
    "      if (!isAtEnd() && input.charAt(index) == '.') {",
    "        floating = true;",
    "        index++;",
    "        while (!isAtEnd() && Character.isDigit(input.charAt(index))) index++;",
    "      }",
    "      if (!isAtEnd() && (input.charAt(index) == 'e' || input.charAt(index) == 'E')) {",
    "        floating = true;",
    "        index++;",
    "        if (!isAtEnd() && (input.charAt(index) == '+' || input.charAt(index) == '-')) index++;",
    "        while (!isAtEnd() && Character.isDigit(input.charAt(index))) index++;",
    "      }",
    "      String text = input.substring(start, index);",
    "      try {",
    "        if (floating) return Double.parseDouble(text);",
    "        long longValue = Long.parseLong(text);",
    "        return longValue >= Integer.MIN_VALUE && longValue <= Integer.MAX_VALUE ? (int) longValue : longValue;",
    "      } catch (NumberFormatException error) {",
    "        throw error(\"Invalid JSON number\");",
    "      }",
    "    }",
    "",
    "    private boolean tryConsume(char expected) {",
    "      if (!isAtEnd() && input.charAt(index) == expected) {",
    "        index++;",
    "        return true;",
    "      }",
    "      return false;",
    "    }",
    "",
    "    private void expect(char expected) {",
    "      if (isAtEnd() || input.charAt(index) != expected) throw error(\"Expected '\" + expected + \"'\");",
    "      index++;",
    "    }",
    "",
    "    private IllegalArgumentException error(String message) {",
    "      return new IllegalArgumentException(message + \" at offset \" + index);",
    "    }",
    "  }",
    "}",
    "",
  ].join("\n");
}

export function emitJavaYaml(packageName: string): string {
  return [
    "// Code generated by Typra emitter; DO NOT EDIT.",
    `package ${packageName};`,
    "",
    "import java.util.ArrayList;",
    "import java.util.LinkedHashMap;",
    "import java.util.List;",
    "import java.util.Map;",
    "",
    "public final class TypraYaml {",
    "  private TypraYaml() { }",
    "",
    "  public static String stringify(Object value) {",
    "    StringBuilder builder = new StringBuilder();",
    "    writeValue(builder, value, 0);",
    "    return builder.toString();",
    "  }",
    "",
    "  public static Object parse(String yaml) {",
    "    return new Parser(yaml).parse();",
    "  }",
    "",
    "  private static void writeValue(StringBuilder builder, Object value, int indent) {",
    "    if (value instanceof Map<?, ?> map) {",
    "      writeMap(builder, map, indent);",
    "      return;",
    "    }",
    "    if (value instanceof Iterable<?> list) {",
    "      writeList(builder, list, indent);",
    "      return;",
    "    }",
    "    appendIndent(builder, indent);",
    "    builder.append(formatScalar(value)).append('\\n');",
    "  }",
    "",
    "  private static void writeMap(StringBuilder builder, Map<?, ?> map, int indent) {",
    "    if (map.isEmpty()) {",
    "      appendIndent(builder, indent);",
    "      builder.append(\"{}\").append('\\n');",
    "      return;",
    "    }",
    "    for (Map.Entry<?, ?> entry : map.entrySet()) {",
    "      appendIndent(builder, indent);",
    "      String key = String.valueOf(entry.getKey());",
    "      Object value = entry.getValue();",
    "      if (value instanceof Map<?, ?> nestedMap) {",
    "        if (nestedMap.isEmpty()) {",
    "          builder.append(formatKey(key)).append(\": {}\").append('\\n');",
    "        } else {",
    "          builder.append(formatKey(key)).append(':').append('\\n');",
    "          writeMap(builder, nestedMap, indent + 2);",
    "        }",
    "      } else if (value instanceof Iterable<?> nestedList) {",
    "        if (isIterableEmpty(nestedList)) {",
    "          builder.append(formatKey(key)).append(\": []\").append('\\n');",
    "        } else {",
    "          builder.append(formatKey(key)).append(':').append('\\n');",
    "          writeList(builder, nestedList, indent + 2);",
    "        }",
    "      } else {",
    "        builder.append(formatKey(key)).append(\": \").append(formatScalar(value)).append('\\n');",
    "      }",
    "    }",
    "  }",
    "",
    "  private static void writeList(StringBuilder builder, Iterable<?> values, int indent) {",
    "    List<Object> snapshot = new ArrayList<>();",
    "    for (Object item : values) snapshot.add(item);",
    "    if (snapshot.isEmpty()) {",
    "      appendIndent(builder, indent);",
    "      builder.append(\"[]\").append('\\n');",
    "      return;",
    "    }",
    "    for (Object item : snapshot) {",
    "      if (item instanceof Map<?, ?> mapItem) {",
    "        if (mapItem.isEmpty()) {",
    "          appendIndent(builder, indent);",
    "          builder.append(\"- {}\").append('\\n');",
    "        } else {",
    "          appendIndent(builder, indent);",
    "          builder.append('-').append('\\n');",
    "          writeMap(builder, mapItem, indent + 2);",
    "        }",
    "      } else if (item instanceof Iterable<?> listItem) {",
    "        if (isIterableEmpty(listItem)) {",
    "          appendIndent(builder, indent);",
    "          builder.append(\"- []\").append('\\n');",
    "        } else {",
    "          appendIndent(builder, indent);",
    "          builder.append('-').append('\\n');",
    "          writeList(builder, listItem, indent + 2);",
    "        }",
    "      } else {",
    "        appendIndent(builder, indent);",
    "        builder.append(\"- \").append(formatScalar(item)).append('\\n');",
    "      }",
    "    }",
    "  }",
    "",
    "  private static boolean isIterableEmpty(Iterable<?> values) {",
    "    return !values.iterator().hasNext();",
    "  }",
    "",
    "  private static void appendIndent(StringBuilder builder, int indent) {",
    "    for (int i = 0; i < indent; i++) builder.append(' ');",
    "  }",
    "",
    "  private static String formatScalar(Object value) {",
    "    if (value == null) return \"null\";",
    "    if (value instanceof Number || value instanceof Boolean) return String.valueOf(value);",
    "    String text = String.valueOf(value);",
    "    if (isPlainString(text)) return text;",
    "    return \"\\\"\" + escape(text) + \"\\\"\";",
    "  }",
    "",
    "  private static String formatKey(String key) {",
    "    if (isPlainKey(key)) return key;",
    "    return \"\\\"\" + escape(key) + \"\\\"\";",
    "  }",
    "",
    "  private static boolean isPlainString(String value) {",
    "    if (value == null || value.isEmpty()) return false;",
    "    String lowered = value.toLowerCase();",
    "    if (\"null\".equals(lowered) || \"~\".equals(value) || \"true\".equals(lowered) || \"false\".equals(lowered)) return false;",
    "    if (looksNumeric(value)) return false;",
    "    for (int i = 0; i < value.length(); i++) {",
    "      char ch = value.charAt(i);",
    "      boolean alphaNum = (ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z') || (ch >= '0' && ch <= '9');",
    "      if (!alphaNum && ch != '_' && ch != '-' && ch != '.' && ch != '/' ) return false;",
    "    }",
    "    return true;",
    "  }",
    "",
    "  private static boolean isPlainKey(String value) {",
    "    if (value == null || value.isEmpty()) return false;",
    "    for (int i = 0; i < value.length(); i++) {",
    "      char ch = value.charAt(i);",
    "      boolean alphaNum = (ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z') || (ch >= '0' && ch <= '9');",
    "      if (!alphaNum && ch != '_' && ch != '-' && ch != '.' && ch != '/') return false;",
    "    }",
    "    return true;",
    "  }",
    "",
    "  private static boolean looksNumeric(String value) {",
    "    if (value == null || value.isEmpty()) return false;",
    "    char first = value.charAt(0);",
    "    if (!((first >= '0' && first <= '9') || first == '-' || first == '+')) return false;",
    "    try {",
    "      if (value.contains(\".\") || value.contains(\"e\") || value.contains(\"E\")) {",
    "        Double.parseDouble(value);",
    "      } else {",
    "        Long.parseLong(value);",
    "      }",
    "      return true;",
    "    } catch (NumberFormatException error) {",
    "      return false;",
    "    }",
    "  }",
    "",
    "  private static String escape(String value) {",
    "    return value.replace(\"\\\\\", \"\\\\\\\\\").replace(\"\\\"\", \"\\\\\\\"\").replace(\"\\n\", \"\\\\n\").replace(\"\\r\", \"\\\\r\").replace(\"\\t\", \"\\\\t\");",
    "  }",
    "",
    "  private static final class Parser {",
    "    private final List<Line> lines = new ArrayList<>();",
    "    private int index;",
    "",
    "    Parser(String yaml) {",
    "      String input = yaml == null ? \"\" : yaml;",
    "      String[] rawLines = input.replace(\"\\r\\n\", \"\\n\").replace('\\r', '\\n').split(\"\\n\", -1);",
    "      for (String rawLine : rawLines) {",
    "        String line = rawLine.stripTrailing();",
    "        if (line.trim().isEmpty()) continue;",
    "        int indent = 0;",
    "        while (indent < line.length() && line.charAt(indent) == ' ') indent++;",
    "        lines.add(new Line(indent, line.substring(indent).trim()));",
    "      }",
    "    }",
    "",
    "    Object parse() {",
    "      if (lines.isEmpty()) return new LinkedHashMap<String, Object>();",
    "      String first = lines.get(0).content;",
    "      if (first.startsWith(\"{\") || first.startsWith(\"[\")) return TypraJson.parse(first);",
    "      if (lines.size() == 1 && !first.startsWith(\"-\")) {",
    "        if (first.startsWith(\"\\\"\") || first.startsWith(\"'\")) return parseScalar(first);",
    "        if (!first.contains(\": \")) return parseScalar(first);",
    "      }",
    "      Object value = parseBlock(lines.get(0).indent);",
    "      if (index < lines.size()) throw error(\"Unexpected trailing YAML content\");",
    "      return value;",
    "    }",
    "",
    "    private Object parseBlock(int indent) {",
    "      if (index >= lines.size()) return null;",
    "      Line line = lines.get(index);",
    "      if (line.indent < indent) return null;",
    "      if (line.content.startsWith(\"-\")) return parseList(indent);",
    "      return parseMap(indent);",
    "    }",
    "",
    "    private Map<String, Object> parseMap(int indent) {",
    "      Map<String, Object> result = new LinkedHashMap<>();",
    "      while (index < lines.size()) {",
    "        Line line = lines.get(index);",
    "        if (line.indent < indent) break;",
    "        if (line.indent > indent) throw error(\"Unexpected indentation\");",
    "        if (line.content.startsWith(\"-\")) throw error(\"Unexpected list item in map\");",
    "        int separator = findMapSeparator(line.content);",
    "        if (separator < 0) throw error(\"Expected ':' in map entry\");",
    "        String key = parseKey(line.content.substring(0, separator).trim());",
    "        String remainder = line.content.substring(separator + 1).trim();",
    "        index++;",
    "        if (!remainder.isEmpty()) {",
    "          result.put(key, parseScalar(remainder));",
    "          continue;",
    "        }",
    "        if (index >= lines.size() || lines.get(index).indent <= indent) {",
    "          result.put(key, null);",
    "          continue;",
    "        }",
    "        result.put(key, parseBlock(lines.get(index).indent));",
    "      }",
    "      return result;",
    "    }",
    "",
    "    private List<Object> parseList(int indent) {",
    "      List<Object> result = new ArrayList<>();",
    "      while (index < lines.size()) {",
    "        Line line = lines.get(index);",
    "        if (line.indent < indent) break;",
    "        if (line.indent > indent) throw error(\"Unexpected indentation\");",
    "        if (!line.content.startsWith(\"-\")) break;",
    "        String remainder = line.content.length() == 1 ? \"\" : line.content.substring(1).trim();",
    "        index++;",
    "        if (!remainder.isEmpty()) {",
    "          result.add(parseScalar(remainder));",
    "          continue;",
    "        }",
    "        if (index >= lines.size() || lines.get(index).indent <= indent) {",
    "          result.add(null);",
    "          continue;",
    "        }",
    "        result.add(parseBlock(lines.get(index).indent));",
    "      }",
    "      return result;",
    "    }",
    "",
    "    private Object parseScalar(String text) {",
    "      if (text == null || text.isEmpty()) return \"\";",
    "      if (\"null\".equalsIgnoreCase(text) || \"~\".equals(text)) return null;",
    "      if (\"true\".equalsIgnoreCase(text)) return Boolean.TRUE;",
    "      if (\"false\".equalsIgnoreCase(text)) return Boolean.FALSE;",
    "      if (\"{}\".equals(text)) return new LinkedHashMap<String, Object>();",
    "      if (\"[]\".equals(text)) return new ArrayList<Object>();",
    "      if (text.startsWith(\"\\\"\") && text.endsWith(\"\\\"\") && text.length() >= 2) return unescapeDoubleQuoted(text.substring(1, text.length() - 1));",
    "      if (text.startsWith(\"'\") && text.endsWith(\"'\") && text.length() >= 2) return text.substring(1, text.length() - 1).replace(\"''\", \"'\");",
    "      if (looksNumeric(text)) {",
    "        try {",
    "          if (text.contains(\".\") || text.contains(\"e\") || text.contains(\"E\")) return Double.parseDouble(text);",
    "          long longValue = Long.parseLong(text);",
    "          return longValue >= Integer.MIN_VALUE && longValue <= Integer.MAX_VALUE ? (int) longValue : longValue;",
    "        } catch (NumberFormatException error) {",
    "          return text;",
    "        }",
    "      }",
    "      return text;",
    "    }",
    "",
    "    private String unescapeDoubleQuoted(String value) {",
    "      StringBuilder result = new StringBuilder();",
    "      for (int i = 0; i < value.length(); i++) {",
    "        char ch = value.charAt(i);",
    "        if (ch != '\\\\' || i + 1 >= value.length()) {",
    "          result.append(ch);",
    "          continue;",
    "        }",
    "        char next = value.charAt(++i);",
    "        switch (next) {",
    "          case 'n' -> result.append('\\n');",
    "          case 'r' -> result.append('\\r');",
    "          case 't' -> result.append('\\t');",
    "          case '\\\\' -> result.append('\\\\');",
    "          case '\"' -> result.append('\"');",
    "          default -> result.append(next);",
    "        }",
    "      }",
    "      return result.toString();",
    "    }",
    "",
    "    private String parseKey(String keyText) {",
    "      if (keyText.startsWith(\"\\\"\") && keyText.endsWith(\"\\\"\") && keyText.length() >= 2) {",
    "        return unescapeDoubleQuoted(keyText.substring(1, keyText.length() - 1));",
    "      }",
    "      if (keyText.startsWith(\"'\") && keyText.endsWith(\"'\") && keyText.length() >= 2) {",
    "        return keyText.substring(1, keyText.length() - 1).replace(\"''\", \"'\");",
    "      }",
    "      return keyText;",
    "    }",
    "",
    "    private int findMapSeparator(String content) {",
    "      boolean inSingle = false;",
    "      boolean inDouble = false;",
    "      boolean escaped = false;",
    "      for (int i = 0; i < content.length(); i++) {",
    "        char ch = content.charAt(i);",
    "        if (escaped) {",
    "          escaped = false;",
    "          continue;",
    "        }",
    "        if (ch == '\\\\' && inDouble) {",
    "          escaped = true;",
    "          continue;",
    "        }",
    "        if (ch == '\"' && !inSingle) {",
    "          inDouble = !inDouble;",
    "          continue;",
    "        }",
    "        if (ch == '\\'' && !inDouble) {",
    "          inSingle = !inSingle;",
    "          continue;",
    "        }",
    "        if (ch == ':' && !inSingle && !inDouble) return i;",
    "      }",
    "      return -1;",
    "    }",
    "",
    "    private IllegalArgumentException error(String message) {",
    "      return new IllegalArgumentException(message + \" at line \" + (index + 1));",
    "    }",
    "  }",
    "",
    "  private static final class Line {",
    "    private final int indent;",
    "    private final String content;",
    "",
    "    private Line(int indent, String content) {",
    "      this.indent = indent;",
    "      this.content = content;",
    "    }",
    "  }",
    "}",
    "",
  ].join("\n");
}
